import * as React from 'react';
import { useStaticQuery, graphql, navigate } from 'gatsby';
import Box from '@mui/material/Box';
import Link from '@mui/material/Link';
import Layout from '../../components/layout';
import SectionMenu from '../../components/sections/menu';
import Thumbnails from '../../components/thumbnails';
import { Seo } from '../../components/seo';

const WorksPage = props => {
  const param = new URLSearchParams(props.location.search);
  const category = param.get('category');

  const worksThumbnails = useStaticQuery(graphql`
    {
      allFile(filter: { relativeDirectory: { eq: "works-thumbnails" } }) {
        edges {
          node {
            childImageSharp {
              gatsbyImageData(width: 400, placeholder: BLURRED)
            }
            name
          }
        }
      }
    }
  `);

  const get = (name, category = '') => {
    const [, _link] = name.match(/^portfolio_works_(.+)_00$/);
    const link = _link.replace(/_/g, '-');

    const [{ node }] = worksThumbnails.allFile.edges.filter(
      worksThumbnail => worksThumbnail.node.name === name
    );

    return {
      name: node?.name,
      image: node?.childImageSharp?.gatsbyImageData,
      link,
      category
    };
  };

  const datas = [
    get('portfolio_works_20230104_interior-2_00'),
    get('portfolio_works_20230104_interior-1_00'),
    get('portfolio_works_20230103_interior-1_00'),
    get('portfolio_works_20230101_interior-1_00'),
    get('portfolio_works_20221201_portrait-1_00', 'portrait'),
    get('portfolio_works_20221105_wosaka-7_00', 'hotel'),
    get('portfolio_works_20221105_wosaka-6_00', 'hotel'),
    get('portfolio_works_20221105_wosaka-5_00', 'hotel'),
    get('portfolio_works_20221105_wosaka-4_00', 'hotel'),
    get('portfolio_works_20221105_wosaka-3_00', 'hotel'),
    get('portfolio_works_20221105_wosaka-2_00', 'hotel'),
    get('portfolio_works_20221105_wosaka-1_00', 'hotel'),
    get('portfolio_works_20221030_streetsnap-1_00'),
    get('portfolio_works_20221020_portrait-1_00', 'portrait'),
    get('portfolio_works_20221010_ritzokinawa-1_00', 'hotel'),
    get('portfolio_works_20220910_hotelthemitsuikyoto-1_00', 'hotel'),
    get('portfolio_works_20220826_stregisosaka-3_00', 'hotel'),
    get('portfolio_works_20220826_stregisosaka-2_00', 'hotel'),
    get('portfolio_works_20220826_stregisosaka-1_00', 'hotel'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-4_00', 'hotel'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-3_00', 'hotel'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-2_00', 'hotel'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-1_00', 'hotel'),
    get('portfolio_works_20220512_interior-1_00'),
    get('portfolio_works_20210824_interior-1_00'),
    get('portfolio_works_20210614_interior-1_00'),
    get('portfolio_works_20201030_streetsnap-1_00')
  ];

  return (
    <Layout>
      <SectionMenu />
      <Box
        mt={10} // header 分
        mb={4} // thumbnail の spacing 分
        sx={{
          display: 'flex',
          justifyContent: 'center'
        }}
      >
        {[
          {
            label: 'All',
            link: '/works/'
          },
          { label: 'Hotel', link: '/works/?category=hotel', category: 'hotel' },
          {
            label: 'Portrait',
            link: '/works/?category=portrait',
            category: 'portrait'
          }
        ].map(({ label, category: _category }, i) => {
          const link = `/works/${_category ? `?category=${_category}` : ''}`;
          const isCurrent = (!category && !_category) || _category === category;

          return (
            <Link
              key={i}
              href={link}
              onClick={e => {
                e.preventDefault();
                navigate(link);
              }}
              sx={{
                mx: 3,
                textDecoration: isCurrent && 'underline',
                pointerEvents: isCurrent && 'none'
              }}
            >
              {label}
            </Link>
          );
        })}
      </Box>
      <Thumbnails datas={datas} category={category} />
    </Layout>
  );
};

export default WorksPage;

export const Head = () => {
  return <Seo title='WORKS' />;
};
